package travelcare_agent.evaluation.scoring; public record ScoreResult(String scorer,boolean passed,int score,Object expected,Object actual,String reason,boolean applied){public static ScoreResult skipped(String n){return new ScoreResult(n,true,1,null,null,"expectation not configured, scorer skipped",false);} public static ScoreResult of(String n,boolean p,Object e,Object a,String r){return new ScoreResult(n,p,p?1:0,e,a,r,true);}}
